export function SessionHistory({ onClose }: SessionHistoryProps) {
  const [records, setRecords] = useState<OrchestrationRecord[]>([]);
  const [loading, setLoading] = useState(true);
  const panelRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
